#include <bits/stdc++.h>
using namespace std;
int main(){
    int n,ans=1;char a[130],sans[130];
    cin>>n;
    cin>>a;
    strcpy(sans,a);
    for(int i=1;i<n;i++){
        cin>>a;
        if(strlen(a)>strlen(sans) || strlen(a)==strlen(sans) && strcmp(a,sans)>0){
            strcpy(sans,a);
            ans=i+1;
        }
    }
    cout<<ans<<endl<<sans;
    return 0;
}
